 1→import React, { useState, useRef, useEffect } from 'react';
 2→import NODE_COLORS from './nodeColors';
 3→
 4→function SearchBar({ nodes, onSelect }) {
 5→  const [query, setQuery] = useState('');
 6→  const [results, setResults] = useState([]);
 7→  const [open, setOpen] = useState(false);
 8→  const ref = useRef();
 9→
10→  useEffect(() => {
11→    function handleClick(e) {
12→      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
13→    }
14→    document.addEventListener('mousedown', handleClick);
15→    return () => document.removeEventListener('mousedown', handleClick);
16→  }, []);
17→
18→  const handleChange = (e) => {
19→    const q = e.target.value;
20→    setQuery(q);
21→    if (q.length < 2) { setResults([]); setOpen(false); return; }
22→    const lower = q.toLowerCase();
23→    const matches = nodes
24→      .filter(n => n.label.toLowerCase().includes(lower) || n.id.toLowerCase().includes(lower) ||
25→        (n.metadata && Object.values(n.metadata).some(v => String(v).toLowerCase().includes(lower))))
26→      .slice(0, 20);
27→    setResults(matches);
28→    setOpen(matches.length > 0);
29→  };
30→
31→  return (
32→    <div className="search-bar" ref={ref}>
33→      <input
34→        placeholder="Search by ID, name, or keyword..."
35→        value={query}
36→        onChange={handleChange}
37→        onFocus={() => results.length > 0 && setOpen(true)}
38→      />
39→      {open && (
40→        <div className="search-results">
41→          {results.map(n => (
42→            <div key={n.id} className="search-result-item" onClick={() => {
43→              onSelect(n.id);
44→              setOpen(false);
45→              setQuery('');
46→            }}>
47→              <span className="search-type-badge" style={{ background: NODE_COLORS[n.type]?.border || '#666' }}>
48→                {n.type}
49→              </span>
50→              <span className="search-result-label">{n.label}</span>
51→            </div>
52→          ))}
53→        </div>
54→      )}
55→    </div>
56→  );
57→}
58→
59→export default SearchBar;
